import { TravixDecimal__Output as TravixDecimal } from '@xivart/proto-postsale/types/travix/postsale/common/v1/TravixDecimal';

import { SeatAssignmentStatus } from '../postSale/constants';
import {
  AckCodeType,
  ErrorClassificationCodeType,
  OfferLocationEnum,
  SeverityCodeType,
} from './shop.constants';
import { SeatCharacteristicsAPI } from '../seatMap/schemas/seatCharacteristics.api.type';

export interface ShopAsyncRequestType {
  /**
   * 请求头信息
   */
  readonly requestHeader: RequestHeader;
  /**
   * 请求体信息
   */
  readonly requestBody: ShopRequestBody;
}
export interface ShopAsyncResponseType {
  /**
   * 响应状态, 首先对ACK信息处理，若为Success,则相应成功。若为Failure,查看error
   * s参考更详细的错误码和错误信息
   */
  readonly responseStatus: ResponseStatusType;
  /**
   * 响应头信息
   */
  readonly responseHeader: ResponseHeader;
  /**
   * 响应数据
   */
  readonly responseBody: ShopResponseBody;
  /**
   * 业务状态信息
   */
  readonly businessStatus: BusinessStatus;
}
export interface BusinessStatus {
  /**
   * 是否成功
   */
  readonly success: boolean;
  /**
   * 错误信息
   */
  readonly error: Error;
}
export interface Error {
  /**
   * 错误码
   */
  readonly errorCode: string;
  /**
   * 错误信息
   */
  readonly errorMessage: string;
}
export interface ShopResponseBody {
  /**
   * Airhelp产品
   */
  readonly airhelp: ShopAirhelpResponse;
  /**
   * checkin产品
   */
  readonly autoCheckIn: ShopAutoCheckInResponse;
  /**
   * seat产品
   */
  readonly seat: ShopSeatResponse;
  /**
   * Fee产品
   */
  readonly fee: ShopFeeResponse;
  /**
   * SP产品
   */
  readonly servicePackage: ShopServicePackageResponse;
  /**
   * 供应商Hepstar，Ins产品
   */
  readonly insurance: ShopInsuranceResponse;
  /**
   * 供应商Hepstar，RP产品
   */
  readonly refundProtect: ShopRefundProtectResponse;
  /**
   * 行李产品
   */
  readonly baggage: ShopBaggageResponse;
  /**
   * Ftg产品
   */
  readonly ticketGuarantee: ShopFtgResponse;
  /**
   * cfar产品
   */
  readonly cfar: ShopCfarResponse;
}
export interface ShopCfarResponse {
  /**
   * ID
   */
  readonly id: string;
  /**
   * 可售方案列表
   */
  readonly purchaseOptions: readonly OfferPurchaseOption[];
  /**
   * USP文案
   */
  readonly translatedContent: OfferTranslatedContent;
}
export interface OfferTranslatedContent {
  readonly usps: readonly UspItem[];
}
export interface UspItem {
  readonly text: string;
}
export interface OfferPurchaseOption {
  readonly id: string;
  /**
   * 产品费率信息
   */
  readonly rate: BasicRate;
  readonly coveragePercentage: string;
}
export interface BasicRate {
  /**
   * 产品总价
   */
  readonly price: Price;
  /**
   * 每人价格
   */
  readonly pricePerPerson: Price;
}
export interface Price {
  /**
   * 金额
   */
  readonly amount: number;
  /**
   * 币种
   */
  readonly currency: string;
}
export interface ShopFtgResponse {
  readonly id: string;
  /**
   * 是否已选中（可为空）
   */
  readonly selected: boolean;
  /**
   * 用户是否主动选择（可为空）
   */
  readonly userSelection: boolean;
  /**
   * 费用明细列表
   */
  readonly costs: readonly BasicRate[];
  /**
   * 是否展示提醒
   */
  readonly showReminder: boolean;
}
export interface ShopBaggageResponse {
  readonly legs: readonly any[]; // Legs在account这边没有用 但是契约里有所以给个占位符
  readonly items: readonly BaggageOptionsModel[];
}

export interface BaggageOptionsModel {
  readonly passengerId: number;
  readonly passengerType: string;
  readonly checkedBaggageOptions: readonly BaggageOptionModel[];
  readonly cabinBaggageOptions: readonly BaggageOptionModel[];
  readonly personalItemOptions: readonly BaggageOptionModel[];
}

export interface BaggageOptionModel {
  readonly legsIds: readonly number[];
  readonly pnr: string;
  readonly pnrId: number;
  readonly needSelfTransfer: boolean;
  readonly transferTimeTooShort: boolean;
  readonly defaultBaggage: DefaultBaggage;
  readonly selectedBaggage: SelectedBaggage;
  readonly items: readonly BaggageOptionItem[];
  readonly baggageDetails: readonly BaggageDetailItem[];
}

export interface BaggageDetailItem {
  readonly segmentId: number;
  readonly status: number;
  readonly weight: number;
  readonly pieces: number;
  readonly unit: string;
  readonly code: string;
  readonly cost: BaggageOptionCost;
  readonly baggageRestriction: BaggageRestriction;
}

export interface BaggageRestriction {
  readonly sumOfDimensions: number;
  readonly length: number;
  readonly width: number;
  readonly height: number;
  readonly unit: string;
  readonly type: string;
}

export interface BaggageOptionCost {
  readonly currencyCode: string;
  readonly amountTotal: string;
  readonly amountTotalPerOneWay: string;
  readonly amount: string;
  readonly amountPerOneWay: string;
  readonly markup: string;
  readonly markupPerOneWay: string;
  readonly additionalCosts: string;
  readonly additionalCostsPerOneWay: string;
  readonly originalAmount: string;
  readonly discountAmount: string;
}

export interface BaggageOptionItem {
  readonly code: string;
  readonly pieces: number;
  readonly weight: number;
  readonly pbrEventName: string;
  readonly provider: string;
  readonly cost: BaggageOptionCost;
  readonly bundleOfferType: string;
  readonly specificBundleCode: string;
  readonly baggageRestriction: BaggageRestriction;
}

export interface SelectedBaggage {
  readonly code: string;
  readonly bundleCode: string;
}

export interface DefaultBaggage {
  readonly included: boolean;
  readonly quantity: number;
  readonly weight: number;
  readonly unit: string;
  readonly amount: string;
  readonly status: number;
  readonly baggageRestriction: BaggageRestriction;
}

export interface ShopRefundProtectResponse {
  readonly refundProtects: readonly RefundProtect[];
  readonly selectedPaidProduct: boolean;
}
export interface RefundProtect {
  readonly id: string;
  readonly name: string;
  readonly nameV2: string;
  readonly productKey: string;
  readonly currency: string;
  readonly packageQuotes: readonly RefundProtectPackageQuote[];
  readonly providerName: string;
  readonly providerCode: string;
  readonly basePrice: number;
  readonly tax: number;
  readonly disclosureV2: string;
}
export interface RefundProtectPackageQuote {
  readonly type: string;
  readonly category: string;
  readonly description: string;
  readonly policyCost: number;
  readonly priceWithServiceCost: number;
  readonly purchasePricePerPerson: number;
  readonly items: readonly string[];
  readonly policyWordingUrl: string;
  readonly optionText: string;
  readonly noInsuranceText: string;
  readonly insurer: Insurer;
  readonly productCovers: readonly ProductCover[];
  readonly highlight: Highlight;
  readonly termsAndConditionsLink: string;
}
export interface Highlight {
  readonly text: string;
  readonly highlightProduct: boolean;
}
export interface ProductCover {
  readonly header: string;
  readonly items: readonly Item[];
}
export interface Item {
  readonly description: string;
  readonly currency: string;
  readonly amount: string;
}
export interface Insurer {
  readonly name: string;
  readonly logoURL: string;
  readonly code: string;
  readonly phone: string;
  readonly email: string;
  readonly address: string;
  readonly province: string;
