import { DeckAPI, SeatAPI } from '../types/seat.type';

export const flatSeatMap = (decksData: readonly DeckAPI[]) => {
  const seatApis = decksData
    .flatMap(({ compartments }) => compartments)
    .flatMap(({ rows }) => rows)
    .flatMap(({ seats }) => seats);

  const seatMap: { [key: string]: SeatAPI } = {};

  seatApis.forEach((seat) => {
    seatMap[seat.key] = seat;
  });

  return seatMap;
};

