  readonly code: string;
  readonly reason: string;
}
export interface ExtensionType {
  /**
   * ExtensionType
   */
  readonly Id: string;
  /**
   * ExtensionType
   */
  readonly Version: string;
  /**
   * ExtensionType
   */
  readonly ContentType: string;
  /**
   * ExtensionType
   */
  readonly Value: string;
}
export interface ErrorDataType {
  readonly Message: string;
  /**
   * A unique code that identifies the particular error
   *  condition that occurred.
   */
  readonly ErrorCode: string;
  /**
   * ErrorDataType
   */
  readonly StackTrace: string;
  /**
   * ErrorDataType
   */
  readonly SeverityCode: SeverityCodeType;
  /**
   * ErrorDataType
   */
  readonly ErrorFields: ErrorFieldType;
  /**
   * ErrorDataType
   */
  readonly ErrorClassification: ErrorClassificationCodeType;
}
export interface ErrorFieldType {
  /**
   * ErrorFieldType
   */
  readonly FieldName: string;
  /**
   * ErrorFieldType
   */
  readonly ErrorCode: string;
  /**
   * ErrorFieldType
   */
  readonly Message: string;
}
export interface ShopRequestBody {
  /**
