   */
  readonly useCache: boolean;
  /**
   * [必] 查找的产品类型：1-Flight,8-Baggage,17-CTCInsurance,20-
   * AutoCheckIn,31-Seat,110-Car,125-AirHelp,1041-CFAR,
   * 1050-TicketGuarantee,1051-ServicePackage,1057-Refu
   * ndProtect,1015-CabinBaggage,1013-STP, 1006-SgrFee,
   *  1055-CalamityFee
   */
  readonly productType: number;
  /**
   * scene=1|2,  Inflow流程和PostSale流程, 提供shoppingCartId
   */
  readonly shoppingCartId: string;
  /**
   * scene=3, SRP页面, 提供fareInfo
   */
  readonly fareInfo: FareInfo;
}
