import { TravixDecimal__Output as TravixDecimal } from '@xivart/proto-postsale/types/travix/postsale/common/v1/TravixDecimal';

import { SeatAssignmentStatus } from '../postSale/constants';
import {
  AckCodeType,
  ErrorClassificationCodeType,
  OfferLocationEnum,
  SeverityCodeType,
} from './shop.constants';
import { SeatCharacteristicsAPI } from '../seatMap/schemas/seatCharacteristics.api.type';

export interface ShopAsyncRequestType {
  /**
   * 请求头信息
   */
  readonly requestHeader: RequestHeader;
  /**
   * 请求体信息
   */
  readonly requestBody: ShopRequestBody;
}
export interface ShopAsyncResponseType {
  /**
   * 响应状态, 首先对ACK信息处理，若为Success,则相应成功。若为Failure,查看error
   * s参考更详细的错误码和错误信息
   */
  readonly responseStatus: ResponseStatusType;
  /**
   * 响应头信息
   */
  readonly responseHeader: ResponseHeader;
  /**
   * 响应数据
   */
  readonly responseBody: ShopResponseBody;
  /**
   * 业务状态信息
   */
  readonly businessStatus: BusinessStatus;
}
export interface BusinessStatus {
  /**
   * 是否成功
   */
  readonly success: boolean;
  /**
   * 错误信息
   */
  readonly error: Error;
}
export interface Error {
  /**
   * 错误码
   */
  readonly errorCode: string;
  /**
   * 错误信息
   */
  readonly errorMessage: string;
}
export interface ShopResponseBody {
  /**
   * Airhelp产品
   */
  readonly airhelp: ShopAirhelpResponse;
  /**
   * checkin产品
   */
  readonly autoCheckIn: ShopAutoCheckInResponse;
  /**
   * seat产品
   */
  readonly seat: ShopSeatResponse;
  /**
   * Fee产品
   */
  readonly fee: ShopFeeResponse;
  /**
   * SP产品
   */
  readonly servicePackage: ShopServicePackageResponse;
  /**
   * 供应商Hepstar，Ins产品
   */
  readonly insurance: ShopInsuranceResponse;
  /**
   * 供应商Hepstar，RP产品
   */
  readonly refundProtect: ShopRefundProtectResponse;
  /**
   * 行李产品
   */
  readonly baggage: ShopBaggageResponse;
  /**
   * Ftg产品
   */
  readonly ticketGuarantee: ShopFtgResponse;
  /**
   * cfar产品
   */
  readonly cfar: ShopCfarResponse;
}
export interface ShopCfarResponse {
  /**
   * ID
   */
  readonly id: string;
  /**
   * 可售方案列表
   */
  readonly purchaseOptions: readonly OfferPurchaseOption[];
  /**
   * USP文案
   */
