  readonly priceWithServiceCost: number;
  readonly purchasePricePerPerson: number;
  readonly items: readonly string[];
  readonly excludedItems: readonly string[];
  readonly policyWordingUrl: string;
  readonly precontract: string;
  readonly benefitsLink: string;
  readonly ipid: string;
  readonly minimalDisclosure: readonly string[];
  readonly topLegalStatement: string;
