export const seatPassengersTransform = {
  toEntity: ({
    passengersApi,
    segmentId,
    decksApi,
  }: SeatPassengersTransformPayload): readonly SeatPassengerWithDetail[] => {
    const passengers: SeatPassengerWithDetail[] = [];

    passengersApi.forEach((passengerApi) =>
      passengers.push({
        passengerIndex: `${passengerApi.id}`,
        seatAssignments: seatAssignmentsTransform.toEntity({
