import { Passenger as AccountPassenger } from '~app/domain/account/passengers/types/passenger.type';
import { Passenger } from '~app/domain/ancillary/postSale/types/passenger.type';
import { purchasedBaggageTransform } from './purchasedBaggage.transform';
import { purchasedSeatTransform } from '~app/domain/ancillary/postSale/transforms/purchasedSeat.transform';
import { BookingSeat } from '~app/domain/account/flight-details/types/bookingSeat.type';
import { SeatAssignment } from '~app/domain/account/passengers/types/seatAssignment.type';

export const passengerTransform = {
  toEntity: (
    bookingPassenger: AccountPassenger,
    pnr: string,
    pnrId: string,
    seatSummary: readonly BookingSeat[],
  ): Passenger => {
    const {
      frequentFlyer,
      passengerReference,
      id,
      luggage,
      identityDocument,
      ...passenger
    } = bookingPassenger;

    const seats: readonly SeatAssignment[] = seatSummary
      .filter((summary) => summary?.passengerIndex === id)
      .map(({ seatKey: seat, segmentId }) => ({
        seat,
        segmentId,
      }));

    return {
      ...passenger,
      passengerIndex: id,
      baggage: luggage?.map((item) => purchasedBaggageTransform.toEntity(item, pnr, pnrId)) || [],
      seat: purchasedSeatTransform.toEntity(seats, pnrId),
      passengerReference,
    };
  },
};

