import {
  seatPassengersApiFixture,
  seatPassengersWithDetailsFixture,
} from '../__fixtures__/seatPassengers.fixture';
import { seatPassengersTransform } from '../seatPassengers.transform';
import { decksApiFixture } from '../__fixtures__/decks.fixture';

describe('seatPassengersTransform', () => {
  describe('toEntity', () => {
    it('should transform the correct data', () => {
      const result = seatPassengersTransform.toEntity({
        passengersApi: seatPassengersApiFixture,
        segmentId: 1,
        decksApi: decksApiFixture,
      });

      expect(result).toStrictEqual(seatPassengersWithDetailsFixture);
    });
  });
});

