import { seatRowTransform } from '../seatRow.transform';
import { seatTransform } from '../seat.transform';
import { seatPassengersWithDetailsFixture } from '../__fixtures__/seatPassengers.fixture';
import {
  compartmentsApiFixture,
  compartmentsWithEmptyRowsApiFixture,
} from '../__fixtures__/seatRows.fixture';

describe('seatRowTransform', () => {
  (seatTransform.toEntity as jest.Mock) = jest.fn(() => 'Seats');

  const segmentId = 0;

  const [
    {
      rows: [{ number: rowNumber }],
    },
  ] = compartmentsApiFixture;

  describe('toEntity', () => {
    it('should transform data and call required transforms', () => {
      const result = seatRowTransform.toEntity(
        compartmentsApiFixture,
        seatPassengersWithDetailsFixture,
        segmentId,
      );

      expect(seatTransform.toEntity).toHaveBeenCalledWith(
        seatPassengersWithDetailsFixture,
        compartmentsApiFixture[0].rows[0],
        {
          WINDOW: 'window',
        },
        segmentId,
      );
      expect(result).toEqual([
        {
          hasBulkhead: false,
          hasExit: false,
          hasOverwing: false,
          hasStairs: false,
          key: '0-0',
          number: rowNumber,
          seats: 'Seats',
        },
      ]);
    });

    it('should return data filtered by raw rows value', () => {
      const result = seatRowTransform.toEntity(
        compartmentsWithEmptyRowsApiFixture,
        seatPassengersWithDetailsFixture,
        segmentId,
      );

      expect(result).toEqual([
        {
          hasBulkhead: false,
          hasExit: false,
          hasOverwing: false,
          hasStairs: false,
          key: '0-0',
          number: rowNumber,
          seats: 'Seats',
        },
      ]);
    });

    it('should return undefined if no seat rows was transformed', () => {
      const result = seatRowTransform.toEntity([], seatPassengersWithDetailsFixture, 1);

      expect(result).toBeUndefined();
    });
  });
});

