import {
  baggageProductDetailTransform,
  seatProductDetailTransform,
} from '~app/domain/ancillary/postSale/transforms/productDetail.transform';
import { ExtraProductInfo } from '~app/domain/ancillary/postSale/schemas/shoppingCart.api.schema';

describe('productDetailTransform', () => {
  describe('baggageProductDetail', () => {
    describe('toEntity', () => {
      it('should return transformed data', () => {
        const extraProductInfo: ExtraProductInfo = {
          baggage: {
            weight: 23,
            quantity: 1,
            sequenceIndex: 1,
            passengerReference: 1,
            code: 'code',
            supplierCode: 'supplierCode',
          },
        };
        const result = baggageProductDetailTransform.toEntity(extraProductInfo);

        expect(result).toEqual({
          quantity: 1,
          weight: 23,
        });
      });

      it('should return default values when baggage info is missing', () => {
        const extraProductInfo: ExtraProductInfo = {};
        const result = baggageProductDetailTransform.toEntity(extraProductInfo);

        expect(result).toEqual({
          quantity: 0,
          weight: 0,
        });
      });
    });
  });

  describe('seatProductDetail', () => {
    describe('toEntity', () => {
      it('should return transformed data', () => {
        const extraProductInfo: ExtraProductInfo = {
          seat: {
            segmentNumber: 1,
            passengerReference: 1,
            seatNumber: '1A',
            uniqueId: 'uniqueId',
          },
        };
        const result = seatProductDetailTransform.toEntity('1A', extraProductInfo);

        expect(result).toEqual({ seatKey: '1A', segmentId: 1 });
      });

      it('should return default values when seat info is missing', () => {
        const extraProductInfo: ExtraProductInfo = {};
        const result = seatProductDetailTransform.toEntity('1A', extraProductInfo);

        expect(result).toEqual({ seatKey: '1A', segmentId: 0 });
      });
    });
  });
});

