      const result = passengerTransform.toEntity(
        accountPassengerChildFixture,
        pnr1Fixture,
        pnrId1Fixture,
        seatSummary,
      );

      expect(result).toEqual({
        ...passengerChildFixture,
        seatAssignments: accountPassengerChildFixture.seatAssignments,
      });
    });
  });
});

