  describe('toEntity', () => {
    const seatKey = '1A';
    const segmentIdentifier = 'SEG-001';

    it('should return empty object when passengers array is empty', () => {
      const result = seatPriceMapTransform.toEntity(seatKey, segmentIdentifier, []);

      expect(result).toEqual({});
    });

    it('should return price list with seat prices for each passenger', () => {
      const passengers: readonly SeatPassengerWithDetail[] = [
        {
          passengerIndex: '0',
          type: PassengerTypes.Adult,
          seatAssignments: [],
          seatMapDetails: [
            {
              segmentId: 0,
              segmentIdentifier: 'SEG-001',
              seatDisplayPrices: {
                '1A': { number: '50' },
                '1B': { number: '30' },
              },
              seatCurrency: 'EUR',
              seatPrices: [],
              status: '',
              markUp: { number: '0' },
              currency: 'EUR',
            },
          ],
        },
        {
          passengerIndex: '1',
          type: PassengerTypes.Child,
          seatAssignments: [],
          seatMapDetails: [
            {
              segmentId: 0,
              segmentIdentifier: 'SEG-001',
              seatDisplayPrices: {
                '1A': { number: '25' },
