      const passengers: readonly SeatPassengerWithDetail[] = [
        {
          passengerIndex: '0',
          type: PassengerTypes.Adult,
          seatAssignments: [],
          seatMapDetails: [
            {
              segmentId: 0,
              segmentIdentifier: 'SEG-001',
              seatDisplayPrices: {
                '2A': { number: '50' },
              },
              seatCurrency: 'EUR',
              seatPrices: [],
              status: '',
              markUp: { number: '0' },
              currency: 'EUR',
            },
          ],
        },
      ];

      const result = seatPriceMapTransform.toEntity(seatKey, segmentIdentifier, passengers);

      expect(result).toEqual({
        0: undefined,
      });
