              markUp: { number: '0' },
              currency: 'EUR',
            },
          ],
        },
        {
          passengerIndex: '1',
          type: PassengerTypes.Child,
          seatAssignments: [],
          seatMapDetails: [
            {
              segmentId: 0,
              segmentIdentifier: 'SEG-001',
              seatDisplayPrices: {
                '1A': { number: '25' },
                '1B': { number: '15' },
              },
              seatCurrency: 'EUR',
              seatPrices: [],
              status: '',
              markUp: { number: '0' },
              currency: 'EUR',
            },
          ],
        },
      ];

      const result = seatPriceMapTransform.toEntity(seatKey, segmentIdentifier, passengers);

      expect(result).toEqual({
        0: 50,
        1: 25,
