          type: PassengerTypes.Adult,
          seatAssignments: [],
          seatMapDetails: [
            {
              segmentId: 0,
              segmentIdentifier: 'SEG-001',
              seatDisplayPrices: {
                '2A': { number: '50' },
              },
              seatCurrency: 'EUR',
              seatPrices: [],
              status: '',
              markUp: { number: '0' },
              currency: 'EUR',
            },
          ],
        },
      ];

      const result = seatPriceMapTransform.toEntity(seatKey, segmentIdentifier, passengers);

      expect(result).toEqual({
        0: undefined,
      });
    });

    it('should return undefined for passenger when segment is not found', () => {
      const passengers: readonly SeatPassengerWithDetail[] = [
        {
          passengerIndex: '0',
          type: PassengerTypes.Adult,
          seatAssignments: [],
          seatMapDetails: [
            {
              segmentId: 1,
              segmentIdentifier: 'SEG-002',
              seatDisplayPrices: {
                '1A': { number: '50' },
              },
              seatCurrency: 'EUR',
              seatPrices: [],
              status: '',
              markUp: { number: '0' },
              currency: 'EUR',
            },
          ],
        },
      ];

      const result = seatPriceMapTransform.toEntity(seatKey, segmentIdentifier, passengers);

      expect(result).toEqual({
        0: undefined,
      });
    });

    it('should return undefined for passenger when seatMapDetails is empty', () => {
      const passengers: readonly SeatPassengerWithDetail[] = [
        {
          passengerIndex: '0',
          type: PassengerTypes.Adult,
          seatAssignments: [],
          seatMapDetails: [],
        },
      ];

      const result = seatPriceMapTransform.toEntity(seatKey, segmentIdentifier, passengers);

      expect(result).toEqual({
        0: undefined,
      });
    });

    it('should handle multiple passengers with mixed availability', () => {
      const passengers: readonly SeatPassengerWithDetail[] = [
        {
          passengerIndex: '0',
          type: PassengerTypes.Adult,
