          seatAssignments: [],
          seatMapDetails: [],
        },
        {
          passengerIndex: '2',
          type: PassengerTypes.Infant,
          seatAssignments: [],
          seatMapDetails: [
            {
              segmentId: 1,
              segmentIdentifier: 'SEG-002',
              seatDisplayPrices: {
                '1A': { number: '10' },
              },
              seatCurrency: 'EUR',
              seatPrices: [],
              status: '',
              markUp: { number: '0' },
              currency: 'EUR',
            },
          ],
        },
      ];

      const result = seatPriceMapTransform.toEntity(seatKey, segmentIdentifier, passengers);

      expect(result).toEqual({
        0: 50,
        1: undefined,
        2: undefined,
      });
    });
  });
