import { changeSeatPayloadTransform } from '../changeSeatPayload.transform';
import {
  AncillaryUpdateOperationType,
  AncillaryProductType,
} from '~app/domain/ancillary/constants';

describe('transformToChangeSeatPayload', () => {
  it('should transform single passenger single segment seat selection', () => {
    const payload = {
      orderNumber: 'TEST-12345',
      postSaleShoppingCartId: 'shoppingCartId123',
      seatAssignments: [
        {
          segmentId: 1,
          pnrId: 'PNR123',
          selectedSeatProducts: [
            {
              seatKey: '12A',
              passengerIndex: '1',
            },
          ],
        },
      ],
    };

    const result = changeSeatPayloadTransform(payload);

    expect(result).toEqual({
      operationType: AncillaryUpdateOperationType.Add,
      productType: AncillaryProductType.SEAT,
      orderNumber: 'TEST-12345',
      extended: {
        selectedSeat: {
          passengers: [
            {
              id: 1,
              seatAssignments: [
                {
                  segmentId: 1,
                  seat: '12A',
                },
              ],
            },
          ],
        },
      },
    });
  });

  it('should transform single passenger multiple segments seat selections', () => {
    const payload = {
      orderNumber: 'TEST-67890',
