            {
              seatKey: '15B',
              passengerIndex: '1',
            },
          ],
        },
      ],
    };

    const result = changeSeatPayloadTransform(payload);

    expect(result).toEqual({
      operationType: AncillaryUpdateOperationType.Add,
      productType: AncillaryProductType.SEAT,
      orderNumber: 'TEST-67890',
      extended: {
        selectedSeat: {
          passengers: [
            {
              id: 1,
              seatAssignments: [
                {
                  segmentId: 1,
                  seat: '12A',
                },
                {
                  segmentId: 2,
                  seat: '15B',
                },
              ],
            },
          ],
        },
      },
    });
  });

  it('should transform multiple passengers multiple segments seat selections', () => {
    const payload = {
      orderNumber: 'TEST-MULTI',
      postSaleShoppingCartId: 'shoppingCartId123',
      seatAssignments: [
        {
          segmentId: 1,
