import { SeatAssignmentAPI } from '../schemas/seatAssignment.api.schema';
import { SeatAssignment } from '../types/seatAssignment.type';

export const seatsTransform = {
  toEntity: (
    seatAssignments: readonly SeatAssignmentAPI[] | null,
  ): readonly SeatAssignment[] | undefined => {
    if (!seatAssignments || !seatAssignments.length) {
      return undefined;
    }

    return seatAssignments.map(({ SegmentId, Seat }) => ({ segmentId: SegmentId, seat: Seat }));
  },
};

